var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"말레볼제 홀, <color=#ffd34c>맥크레디 저택</color>\\nAM 01:30\\n학회 비정기 회동 중","JPN":"マーレボルジェホール、<color=#ffd34c>マクレディー家邸宅</color>\\nAM 01:30\\n学会の非定期会合中","ENG":"[[","TWN":"馬爾伯吉廳，<color=#ffd34c>麥克蕾蒂宅邸</color>\\n上午01:30\\n學會臨時動議中","THA":"หอเมลบอล์ก <color=#ffd34c>คฤหาสน์แมกครีดี้</color>\\n01.30 น.\\nระหว่างการประชุมที่ไม่ปกติของสมาคม","VTN":"Sảnh Malebolge, <color=#ffd34c>Dinh Thự MacCready</color>\\n01:30 sáng\\nTrong cuộc họp bất thường của Hiệp Hội","SCN":"马勒勃尔介厅，<color=#ffd34c>麦克雷迪宅邸</color>\\n上午01:30\\n学会不定期会议，进行中","DEU":"Malebolge Halle, <color=#ffd34c>Herrenhaus der Familie MacCready</color>\\n01:30 Uhr nachts\\nInmitten des unregelmäßigen Treffens der Gesellschaft","FRA":"Hall de Malebolge, <color=#ffd34c>Manoir MacCready</color>\\n01h30 du matin\\nAssemblée extraordinaire de la Société"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"앞서 말씀드렸던 대로 학회가 추종하는 지식의 호수란 거대한 정보 집합체.","JPN":"先程お話ししたとおり、学会が追従している知識の湖とは巨大な情報の集合体。","ENG":"As I have mentioned before, The Lake of Knowledge that the Society follows is a massive collection of information.","TWN":"正如我之前說的那樣，學會推崇的知識湖水是個龐大的資訊集合體。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"즉, 정보에 굶주린 존재에 불과합니다.","JPN":"つまり、情報に飢えている存在に過ぎません。","ENG":"In other words, it is nothing but an existence that craves information.","TWN":"也就是說，它只不過是渴望資訊的存在。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"완전한 지식의 호수는 애초에 모순적인 표현입니다.","JPN":"完全な知識の湖というのは最初から矛盾している表現です。","ENG":"Having a \\"complete\\" Lake of Knowledge is a contradictory expression in and of itself.","TWN":"完整的知識湖水，從一開始就是矛盾的表述。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"정보라는 것이 끊임없이 발생하는 이상, 호수는 필연적으로 불완전할 수밖에 없습니다.","JPN":"情報というものは常に生じるものである以上、湖は必然的に不完全であるしかありません。","ENG":"As long as information is constantly being created, the Lake will always be incomplete.","TWN":"只要資訊不斷產生，湖水必然不會完整。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 그 끝없는 허기를 만족시켜 주기 위해 학회는 숱한 범죄까지 저질러 왔죠.","JPN":"ですが、その底なきひもじさを満足させるために学会はあらゆる犯罪を犯してきました。","ENG":"However, the Society has committed heinous crimes just to satisfy this endless hunger.","TWN":"但是為了滿足這沒有盡頭的饑餓感，學會甚至犯下了很多罪行。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……저희 가문이 그 필두였다는 것 역시, 부정할 생각 없습니다.","JPN":"……私の家門がその筆頭であったということもまた、否定するつもりはありません。","ENG":"...As a member of the MacCready family, I do not deny my family spearheaded this movement.","TWN":"……我們家族就是帶頭的，這一點我也不想否認。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇기에 저는 이 자리에서 선언하겠습니다.","JPN":"ですので、今この場で私は宣言いたします。","ENG":"That is why I am here.","TWN":"所以我要在這裡宣佈。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"호수를 찾기 위해서란 명목으로 행해졌던 모든 비인륜적인 행위들….","JPN":"湖を探す名目で行われたすべての非道徳的な行為……","ENG":"To declare that all of the inhumane and evil practices committed in the name of finding this so-called Lake...","TWN":"以尋找湖水的名義犯下的所有不人道行為……"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"특히 영지민의 차별 대우와 인신 공양을 비롯한 모든 악습들은 철저히 청산돼야 한다고.","JPN":"特に領地民の差別待遇や人身御供をはじめとするすべての悪習は徹底的に清算します。","ENG":"Especially the discrimination against the residents and human sacrifice shall be no more.","TWN":"尤其是差別對待領地居民，和活人祭祀在內的所有陋習，都要徹底廢除並清算。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이상입니다. 의견이 있다면 진솔하게 말씀해 주시길.","JPN":"以上です。ご意見がありましたら率直にお話しください。","ENG":"That is all. If you have any opinions, I am all ears.","TWN":"就是這些。有意見的話，請大家照實說出來。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"종교학부장, 아그네스입니다.","JPN":"宗教学部長のアグネスです。","ENG":"My name is Agnes, Dean of Religion.","TWN":"我是宗教學院院長，艾格妮絲。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"저희는 쇠락한 처지라 호수를 찾기는커녕 앞가림도 힘들어서 말이죠.","JPN":"私たちの学部は落ち目で、湖を探すどころか維持するのも精一杯でございまして。","ENG":"We are currently in decline, so we are struggling to keep our department running, let alone find the Lake.","TWN":"我們學院的處境很艱難，別說尋找湖水了，連維持下去都有困難。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"부학회장님의 파격적인 구상을 지지할 수는 없지만, 반대할 이유도 없네요.","JPN":"副学会長の破格的な構想を支持することはできませんが、反対する理由もありません。","ENG":"Although we don't fully support Vice President, we also have no reason to be against it.","TWN":"雖然不能支援副學會長革新的想法，但我們也沒理由反對。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇군요. 의견 감사합니다.","JPN":"そうですか。ご意見、ありがとうございます。","ENG":"I see. Thank you for your input.","TWN":"這樣啊。謝謝你的意見。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"생물학부장, 하이드리히. 말씀 올리겠소.","JPN":"生物学部長のハイドリヒだ。私の考えを言おう。","ENG":"Dean of Biology, Heydrich. I would like to say a few words.","TWN":"我是生物學院院長，海德里希，我有話要說。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};